import { SslData } from "./ssl_data_class";
const Craft = window.Craft;
import { Base } from "./base_class";
import { DomainData } from "./domain_data_class";
const $ = window.jQuery;
function formatTimestamp(timestamp) {
    const date = new Date(timestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffHours / 24);
    if (diffHours < 1) {
        const diffMins = Math.floor(diffMs / (1000 * 60));
        return `${diffMins} minutes ago`;
    }
    else if (diffHours < 24) {
        return `${diffHours} hours ago`;
    }
    else if (diffDays === 1) {
        return 'Yesterday';
    }
    else if (diffDays < 7) {
        return `${diffDays} days ago`;
    }
    else {
        return date.toLocaleDateString();
    }
}
// Expose data globally
window.formatTimestamp = formatTimestamp;
export class BastionDashboard extends Base {
    currentFilter;
    currentPage;
    itemsPerPage;
    popUp = new Craft.Slideout('loading', { autoShow: false, autoOpen: false });
    sslData = new SslData();
    domainData = new DomainData();
    constructor() {
        super();
        this.currentFilter = 'all';
        this.popUp = new Craft.Slideout('loading', { autoShow: false, autoOpen: false });
        this.sslData = new SslData();
        this.domainData = new DomainData();
    }
    init() {
        this.setupEventListeners();
        this.setupToolTips();
    }
    setupToolTips() {
        document.querySelectorAll('.bastion-tooltip').forEach(btn => {
            const el = btn;
            const text = el.dataset.text;
            if (!text.length) {
                return;
            }
            const popup = document.createElement('p');
            popup.innerHTML = text;
            btn.appendChild(popup);
            btn.addEventListener('click', (e) => {
                e.stopPropagation();
                document.querySelectorAll('.bastion-tooltip').forEach(t => {
                    if (t !== e.currentTarget) {
                        t.classList.remove('showed');
                    }
                });
                const target = e.currentTarget;
                target.classList.add('showed');
            });
        });
        // close tooltips when clicking outside
        document.addEventListener('click', e => {
            document.querySelectorAll('.bastion-tooltip').forEach(t => {
                // if click is outside both the tooltip and its popup
                if (!t.contains(e.target)) {
                    t.classList.remove('showed');
                }
            });
        });
    }
    setupEventListeners() {
        // run SSL checks
        document.getElementById('ssl-check-btn').addEventListener('click', () => {
            this.sslData.runSSLCheck();
        });
        document.getElementById('domain-check-btn').addEventListener('click', () => {
            this.domainData.runDomainCheck();
        });
        // Re-run checks button
        document.getElementById('rerun-checks-btn').addEventListener('click', (el) => {
            const url = el.target.dataset.url;
            this.rerunChecks(url);
        });
        // Filter tabs
        document.querySelectorAll('.tab-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                this.setFilter(e.target.dataset.filter);
            });
        });
        document.querySelectorAll('.settings-btn').forEach(btn => {
            btn.addEventListener('click', e => {
                const settings = e.currentTarget.dataset.settings;
                const url = 'actions/craft-bastion/dashboard/' + settings;
                this.showPopUp(url);
            });
        });
    }
    showPopUp(url) {
        const $this = this;
        this.popUp.open();
        this.popUp.$container.html('Loading...');
        fetch(url, {
            headers: { 'X-Requested-With': 'XMLHttpRequest' }
        })
            .then(r => r.text())
            .then(html => {
            this.popUp.$container.html(html);
            this.popUp.updateSizeAndPosition && this.popUp.updateSizeAndPosition();
            Craft.initUiElements(this.popUp.$container);
            let $form = this.popUp.$container.find('form');
            if ($form && $form.length) {
                $form.validate({
                    submitHandler: function (form) {
                        $.ajax({
                            url: '/',
                            method: 'post',
                            data: $(form).serializeArray(),
                            dataType: 'json',
                            cache: false,
                            success: function (data) {
                                if (data.res) {
                                    $this.showToast(data.message, 'success');
                                    $this.popUp.close();
                                    if ($form.attr('id') == 'security-edit') {
                                        document.getElementById('rerun-checks-btn').dispatchEvent(new Event('click'));
                                    }
                                }
                                else {
                                    $this.showToast(data.message, 'error');
                                    for (let field in data.errors) {
                                        let $errors = `<ul id="title-errors" class="errors">                    
                                                                    ` + data.errors[field].map($el => `<li>
                                                                    <span class="visually-hidden">Error:</span>
                                                                    ${$el}
                                                                    </li>`) + `
                                                                
                                                                </ul>`;
                                        $form.find(`#${field}-field`).append($errors);
                                        $form.find(`#${field}`).addClass('error');
                                    }
                                }
                            }
                        });
                    }
                });
            }
        })
            .catch(console.error);
        this.popUp.updateSizeAndPosition && this.popUp.updateSizeAndPosition();
        this.popUp.$container.on('click', '.js-popup-close', () => this.popUp.close());
    }
    getStatusIcon(status) {
        const icons = {
            passed: 'âœ“',
            warning: '!',
            failed: 'âœ•'
        };
        return icons[status] || '?';
    }
    setFilter(filter) {
        this.currentFilter = filter;
        // Update active tab
        document.querySelectorAll('.tab-btn').forEach(btn => {
            btn.classList.remove('active');
            btn.setAttribute('aria-selected', 'false');
        });
        const activeTab = document.querySelector(`[data-filter="${filter}"]`);
        activeTab.classList.add('active');
        activeTab.setAttribute('aria-selected', 'true');
        console.log(filter);
        // Reload table
        //this.loadChecksTable();
        document.querySelectorAll('#checks-tbody .check-row').forEach(row => {
            const rowStatus = row.dataset.status;
            if (rowStatus == filter || filter == 'all') {
                row.classList.remove('hidden');
            }
            else {
                row.classList.add('hidden');
            }
        });
    }
    rerunChecks(url) {
        this.showToast(Craft.t('craft-bastion', 'Re-running security checks') + '...', 'success');
        document.getElementById('content').classList.add('loading');
        const $this = this;
        $.ajax({
            url: url,
            method: 'get',
            dataType: 'json',
            cache: false,
            success: function (data) {
                console.log(data);
                if (data.res) {
                    window.location.reload();
                }
                else {
                    document.getElementById('content').classList.remove('loading');
                    $this.showToast(data.message, 'error');
                }
            }
        });
    }
}
