import { Base } from "./base_class";
const Craft = window.Craft;
export class DependencyAudit extends Base {
    init() {
        this.bindEvents();
    }
    bindEvents() {
        const runScanBtn = document.querySelector('.btn-scan');
        if (runScanBtn) {
            runScanBtn.addEventListener('click', (e) => {
                e.preventDefault();
                this.runScan(runScanBtn);
            });
        }
    }
    async runScan(button) {
        const originalText = button.innerHTML;
        button.disabled = true;
        button.innerHTML = `
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" class="spin">
                <path d="M21 12a9 9 0 11-6.219-8.56"/>
            </svg>
            Scanning...
        `;
        try {
            const data = await this.fetchData('base/dependency-audit-scan', {});
            if (data && data.success) {
                window.location.reload();
            }
            else {
                this.showError(data?.data?.error || Craft.t('craft-bastion', 'Scan failed'));
                button.disabled = false;
                button.innerHTML = originalText;
            }
        }
        catch (error) {
            console.error('Scan error:', error);
            this.showError(Craft.t('craft-bastion', 'Failed to run scan. Please try again.'));
            button.disabled = false;
            button.innerHTML = originalText;
        }
    }
    showError(message) {
        Craft.cp.displayError(message);
    }
}
