const Craft = window.Craft;
export class Base {
    async fetchData(action, data, method = 'POST') {
        let url = `/admin/actions/craft-bastion/${action}`;
        if (method === 'GET' && data) {
            url += `?${data}`;
            data = null;
        }
        console.log('url', url);
        const params = {
            method: method,
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            },
        };
        if (data && !(data instanceof FormData)) {
            const formData = new FormData();
            formData.append(Craft.csrfTokenName, Craft.csrfTokenValue);
            for (let key in data) {
                if (typeof data[key] == 'object') {
                    for (let i in data[key]) {
                        formData.append(key + '[' + i + ']', data[key][i]);
                    }
                }
                else {
                    formData.append(key, data[key]);
                }
            }
            params.body = formData;
        }
        else if (data) {
            params.body = data;
        }
        const request = await fetch(url, params);
        if (request.ok) {
            return await request.json();
        }
        console.log(request);
        this.showToast(`Internal Error: ${request.status}`, 'error');
    }
    getData(action, query = '') {
        return this.fetchData(action, query, 'GET');
    }
    showToast(message, type = 'success') {
        const container = document.getElementById('toast-container');
        const toastId = 'toast-' + Date.now();
        const toast = document.createElement('div');
        toast.id = toastId;
        toast.className = `toast toast-${type}`;
        toast.innerHTML = `
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                ${type === 'success' ?
            '<path d="M20 6L9 17L4 12" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>' :
            '<path d="M12 9V13M12 17H12.01M21 12C21 16.9706 16.9706 21 12 21C7.02944 21 3 16.9706 3 12C3 7.02944 7.02944 3 12 3C16.9706 3 21 7.02944 21 12Z" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>'}
            </svg>
            <span>${message}</span>
            <button class="toast-close" onclick="dashboard.closeToast('${toastId}')">&times;</button>
        `;
        container.appendChild(toast);
        // Auto-remove after 5 seconds
        setTimeout(() => {
            this.closeToast(toastId);
        }, 5000);
    }
    closeToast(toastId) {
        const toast = document.getElementById(toastId);
        if (toast) {
            toast.style.transform = 'translateX(100%)';
            toast.style.opacity = '0';
            setTimeout(() => {
                toast.remove();
            }, 300);
        }
    }
}
