import { Base } from "./base_class";
const Craft = window.Craft;
export class DomainData extends Base {
    constructor() {
        super();
        this.init();
    }
    init() {
        console.log('init DomainData');
    }
    async runDomainCheck(firstRun = true) {
        this.setLoader(true);
        const domainButton = document.getElementById('domain-check-btn');
        console.log(domainButton);
        const buttonInitialText = domainButton.innerText;
        domainButton.innerText = Craft.t('craft-bastion', 'Processing...');
        domainButton.disabled = true;
        const request = await this.getData('dashboard/get-domain-data');
        console.log(request);
        if (request.errors && request.errors.length) {
            const errorsList = request.errors.map((el) => {
                return `<div>${el}</div>`;
            });
            this.showToast(errorsList.join(''), 'error');
            if (document.getElementById('expiry-date')) {
                document.getElementById('expiry-date').classList.remove('loading-grad-box');
                document.getElementById('registrar').classList.remove('loading-grad-box');
                document.getElementById('expiry-date').innerHTML = '--';
                document.getElementById('registrar').innerHTML = '--';
            }
        }
        else {
            this.loadCard(request);
        }
        this.setLoader(false);
        domainButton.innerText = buttonInitialText;
        domainButton.disabled = false;
    }
    loadCard(data) {
        if (document.getElementById('expiry-date')) {
            document.getElementById('expiry-date').innerHTML = `<b>${data.expDate}</b> in <b>${data.remainData.days}</b> days.`;
            if (data.registrantLink) {
                document.getElementById('registrar').innerHTML = `<a href="${data.registrantLink}" target="_blank">${data.registrant}</a>`;
            }
            else {
                document.getElementById('registrar').innerText = data.registrant;
            }
            document.getElementById('domain-info').classList.add(`domain-${data.remainData.status}`);
        }
    }
    setLoader(type = true) {
        if (document.getElementById('expiry-date')) {
            if (type) {
                document.getElementById('expiry-date').classList.add('loading-grad-box');
                document.getElementById('registrar').classList.add('loading-grad-box');
                document.getElementById('expiry-date').innerHTML = 'loading...';
                document.getElementById('registrar').innerHTML = 'loading...';
                document.getElementById('domain-info').classList.remove(`domain-success`);
                document.getElementById('domain-info').classList.remove(`domain-warning`);
                document.getElementById('domain-info').classList.remove(`domain-error`);
            }
            else {
                document.getElementById('expiry-date').classList.remove('loading-grad-box');
                document.getElementById('registrar').classList.remove('loading-grad-box');
            }
        }
    }
}
