import { Base } from "./base_class";
const Craft = window.Craft;
export class SslData extends Base {
    interval;
    constructor() {
        super();
        this.init();
        this.interval = null;
        //this.firstRun = true;
    }
    init() {
        console.log('init SslData');
    }
    async runSSLCheck(firstRun = true) {
        let status = 'in-progress';
        let query = firstRun ? "clearCache=true" : "";
        const sslButton = document.getElementById('ssl-check-btn');
        console.log(sslButton);
        const buttonInitialText = sslButton.innerText;
        sslButton.innerText = Craft.t('craft-bastion', 'Processing...');
        sslButton.disabled = true;
        const request = await this.getData('dashboard/get-ssl-data', query);
        if (request.errors && request.errors.length) {
            const errorsList = request.errors.map((el) => {
                return `<div>${el}</div>`;
            });
            this.showToast(errorsList.join(''), 'error');
            clearInterval(this.interval);
            this.interval = null;
            status = 'error';
        }
        else {
            this.setProcess(true);
            if (request.data && 'status' in request.data && request.data.status === 'READY') {
                clearInterval(this.interval);
                this.interval = null;
                status = 'completed';
                this.setProcess(false);
            }
            this.loadCard(request.data.summary);
        }
        sslButton.innerText = buttonInitialText;
        sslButton.disabled = false;
        console.log(buttonInitialText);
        console.log('interval', this.interval);
        console.log('status', status);
        if (this.interval === null && status === 'in-progress') {
            this.interval = setInterval(async () => {
                const request = await this.runSSLCheck(false);
            }, 3000);
        }
    }
    setProcess($flag) {
        document.getElementById('ssl-flags').classList.remove('hidden');
        if ($flag) {
            document.getElementById('ssl-progress-bar').classList.add('in-process');
            document.getElementById('ssl-details').classList.add('in-process');
            document.getElementById('ssl-details').classList.remove('info-icon');
            document.getElementById('ssl-details').innerHTML = 'Processing...';
        }
        else {
            document.getElementById('ssl-progress-bar').classList.remove('in-process');
            document.getElementById('ssl-details').classList.remove('in-process');
            document.getElementById('ssl-details').classList.add('info-icon');
        }
    }
    loadCard(data) {
        const flags = data.info;
        const grade = data.grade;
        const lastTime = data.lastCheck;
        const progress = data.progress;
        console.log('data', flags);
        const detailsElement = document.getElementById('ssl-details');
        detailsElement.innerHTML = data.message;
        // Update SSL grade
        const gradeElement = document.getElementById('ssl-grade');
        gradeElement.textContent = grade.details;
        gradeElement.className = 'badge badge-' + grade.status;
        console.log(lastTime);
        if (lastTime > 0) {
            const lastTimeCont = document.getElementById('ssl-last-check');
            let newDate = new Date();
            let startTimeNice = this.getRelativeTime(lastTime);
            lastTimeCont.textContent = `Last check: ${startTimeNice}`;
        }
        else {
        }
        document.getElementById('ssl-progress-bar').querySelector('span').style.width = (progress < 5 ? 5 : progress) + '%';
        // Update SSL flags
        const flagsList = document.getElementById('ssl-flags');
        flagsList.innerHTML = flags.map(flag => `
            <li class="icon icon-${flag.status}">
                ${flag.details}
            </li>
        `).join('');
    }
    getRelativeTime = (relativeDate, date = new Date()) => {
        // if relativeDate is a number, we assume it is an UTC timestamp
        if (typeof relativeDate === 'number') {
            // count charachters to check if in seconds or milliseconds
            if (relativeDate.toString().length < 13) {
                relativeDate = relativeDate * 1000;
            }
            // convert to date object
            relativeDate = new Date(relativeDate);
        }
        if (!(relativeDate instanceof Date)) {
            // invalid date, probably still loading
            return '-';
        }
        let units = {
            year: 24 * 60 * 60 * 1000 * 365,
            month: 24 * 60 * 60 * 1000 * 365 / 12,
            day: 24 * 60 * 60 * 1000,
            hour: 60 * 60 * 1000,
            minute: 60 * 1000,
            second: 1000
        };
        let rtf = new Intl.RelativeTimeFormat('en', { numeric: 'auto' });
        let elapsed = relativeDate.getTime() - date.getTime();
        // "Math.abs" accounts for both "past" & "future" scenarios
        for (let u in units) {
            if (Math.abs(elapsed) > units[u] || u === 'second') {
                //return rtf.format(Math.round(elapsed/units[u]), u)
                return rtf.format(Math.round(elapsed / units[u]), u);
            }
        }
    };
}
